export default function RuleEditor() {
  const { variables, setVariable } = useYumina();
  const [input, setInput] = React.useState("");
  const currentRule = String(variables.custom_rule || "No special rules.");

  return (
    <YUI.Panel title="World Rules">
      <p style={{ color: "#9ca3af", fontSize: "13px", marginBottom: "8px" }}>
        Current rule: {currentRule}
      </p>
      <div style={{ display: "flex", gap: "8px" }}>
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type a new rule..."
          style={{
            flex: 1,
            padding: "8px 12px",
            background: "#1e293b",
            border: "1px solid #334155",
            borderRadius: "8px",
            color: "#e2e8f0",
            fontSize: "14px",
            outline: "none",
          }}
          onKeyDown={(e) => {
            if (e.key === "Enter" && input.trim()) {
              setVariable("custom_rule", input.trim());
              setInput("");
            }
          }}
        />
        <YUI.ActionButton
          onClick={() => {
            if (input.trim()) {
              setVariable("custom_rule", input.trim());
              setInput("");
            }
          }}
        >
          Apply
        </YUI.ActionButton>
      </div>
    </YUI.Panel>
  );
}

messageRenderer.tsxCode:
export default function Renderer({ content, renderMarkdown, messageIndex }) {
  const { variables, switchGreeting, setVariable, executeAction } = useYumina();
  const hasChosen = variables.current_route !== "none";

  return (
    <div>
      <div
        style={{ color: "#e2e8f0", lineHeight: 1.7 }}
        dangerouslySetInnerHTML={{ __html: renderMarkdown(content) }}
      />

      {messageIndex === 0 && !hasChosen && (
        <div style={{ display: "flex", gap: "12px", marginTop: "16px" }}>
          <button
            onClick={() => {
              setVariable("current_route", "dark");
              executeAction("choose-dark");
              switchGreeting(1);
            }}
            style={{
              flex: 1,
              padding: "16px",
              background: "linear-gradient(135deg, #1e1b4b, #312e81)",
              border: "1px solid #4338ca",
              borderRadius: "12px",
              color: "#c7d2fe",
              fontSize: "15px",
              fontWeight: "bold",
              cursor: "pointer",
              transition: "transform 0.15s",
            }}
            onMouseOver={(e) => e.currentTarget.style.transform = "scale(1.03)"}
            onMouseOut={(e) => e.currentTarget.style.transform = "scale(1)"}
          >
            Enter the Dark Cave
          </button>

          <button
            onClick={() => {
              setVariable("current_route", "light");
              executeAction("choose-light");
              switchGreeting(2);
            }}
            style={{
              flex: 1,
              padding: "16px",
              background: "linear-gradient(135deg, #365314, #4d7c0f)",
              border: "1px solid #65a30d",
              borderRadius: "12px",
              color: "#ecfccb",
              fontSize: "15px",
              fontWeight: "bold",
              cursor: "pointer",
              transition: "transform 0.15s",
            }}
            onMouseOver={(e) => e.currentTarget.style.transform = "scale(1.03)"}
            onMouseOut={(e) => e.currentTarget.style.transform = "scale(1)"}
          >
            Walk to the Sunlit Meadow
          </button>
        </div>
      )}
    </div>
  );
}
